        current_object = ""
        brace_count = 0
        in_string = False
        escape_next = False

        for line in lines:
            current_object += line + '\n'

            # Count braces to find complete objects
            for char in line:
                if escape_next:
                    escape_next = False
                    continue

                if char == '\\':
                    escape_next = True
                    continue

                if char == '"' and not escape_next:
                    in_string = not in_string
                    continue

                if not in_string:
